import { MakeLogicType, actions, afterMount, connect, kea, listeners, path, reducers } from 'kea'
import { loaders } from 'kea-loaders'

import { teamLogic } from 'scenes/teamLogic'

import { metricsValuesRetrieve } from 'products/metrics/frontend/generated/api'
import type { _MetricNameApi } from 'products/metrics/frontend/generated/api.schemas'
import { canViewMetrics } from 'products/metrics/frontend/metricsAccess'

export type MetricNameItem = _MetricNameApi

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface metricNamePickerLogicValues {
    currentTeamId: number | null // teamLogic
    items: MetricNameItem[]
    itemsLoading: boolean
    search: string
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface metricNamePickerLogicActions {
    loadItems: (_: any) => any
    loadItemsFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadItemsSuccess: (
        items: _MetricNameApi[],
        payload?: any
    ) => {
        items: _MetricNameApi[]
        payload?: any
    }
    setSearch: (search: string) => {
        search: string
    }
}

export type metricNamePickerLogicType = MakeLogicType<metricNamePickerLogicValues, metricNamePickerLogicActions>

export const metricNamePickerLogic = kea<metricNamePickerLogicType>([
    path(['products', 'metrics', 'frontend', 'components', 'metricNamePickerLogic']),
    connect(() => ({
        values: [teamLogic, ['currentTeamId']],
    })),
    actions({
        setSearch: (search: string) => ({ search }),
    }),
    reducers({
        search: ['' as string, { setSearch: (_, { search }) => search }],
    }),
    loaders(({ values }) => ({
        items: [
            [] as MetricNameItem[],
            {
                loadItems: async (_, breakpoint) => {
                    if (!canViewMetrics()) {
                        return []
                    }
                    // Debounce — match the 300ms cadence used in the viewer logic so
                    // both fetches feel cohesive.
                    await breakpoint(300)
                    const response = await metricsValuesRetrieve(String(values.currentTeamId), {
                        value: values.search,
                        limit: 100,
                    })
                    breakpoint()
                    return response.results
                },
            },
        ],
    })),
    listeners(({ actions }) => ({
        setSearch: () => {
            actions.loadItems({})
        },
    })),
    afterMount(({ actions }) => {
        // Prime the list so the dropdown isn't empty on first open. Mirrors
        // serviceFilterLogic's afterMount in logs.
        if (canViewMetrics()) {
            actions.loadItems({})
        }
    }),
])
